export function tokenize(input){const tokens=[];let i=0;const push=(type,value)=>tokens.push({type,value});const isDigit=(c)=>c>="0"&&c<="9";while(i<input.length){const c=input[i];if(/\s/.test(c)){let start=i;while(i<input.length&&/\s/.test(input[i]))i++;push("whitespace",input.slice(start,i));continue} if(c==="/"&&input[i+1]==="/"){let start=i;i+=2;while(i<input.length&&input[i]!=="\n")i++;push("comment",input.slice(start,i));continue} if(c==="/"&&input[i+1]==="*"){let start=i;i+=2;while(i<input.length&&!(input[i]==="*"&&input[i+1]==="/"))i++;i+=2;push("comment",input.slice(start,i));continue} if("{}[]:,".includes(c)){push("punctuator",c);i++;continue} if(c==='"'){let start=i;i++;while(i<input.length){if(input[i]==="\\"){i+=2;continue} if(input[i]==='"'){i++;break} i++} push("string",input.slice(start,i));continue} if(c==="-"||isDigit(c)){let start=i;if(c==="-")i++;if(input[i]==="0"){i++;if(isDigit(input[i])){push("error",input.slice(start,i+1));i++;continue}}else{while(isDigit(input[i]))i++} if(input[i]==="."){i++;if(!isDigit(input[i])){push("error",input.slice(start,i));continue} while(isDigit(input[i]))i++} if(input[i]==="e"||input[i]==="E"){i++;if(input[i]==="+"||input[i]==="-")i++;if(!isDigit(input[i])){push("error",input.slice(start,i));continue} while(isDigit(input[i]))i++} push("number",input.slice(start,i));continue} if(input.startsWith("true",i)){push("keyword","true");i+=4;continue} if(input.startsWith("false",i)){push("keyword","false");i+=5;continue} if(input.startsWith("null",i)){push("keyword","null");i+=4;continue} push("error",c);i++} return tokens}
